{
  "pattern": {
    "name": "crossed_selects_feeding_commutative_op",
    "summary": "If the two operands of a commutative operation are selects on the same condition with swapped true/false values, the select pair can be eliminated because the unordered operand pair is invariant.",
    "match": [
      "%s0 = select i1 %c, T %x, T %y",
      "%s1 = select i1 %c, T %y, T %x",
      "%r = op %s0, %s1"
    ],
    "preconditions": [
      "The two selects use the same condition value.",
      "The selected values are crossed: first select chooses (%x,%y), second chooses (%y,%x).",
      "op is commutative.",
      "Types are compatible with the operation/intrinsic."
    ],
    "rewrite": [
      "%r = op %x, %y"
    ],
    "notes": [
      "This applies to integer and floating-point binary operators where the operator is commutative.",
      "This also applies to commutative intrinsics whose relevant operands are the crossed selects, even if the intrinsic has additional operands.",
      "The fold should preserve binary operator flags such as nuw/nsw/exact where valid, and floating-point fast-math flags.",
      "The fold is valid for scalar and vector forms, including per-lane vector select conditions.",
      "The same canonicalization should work regardless of operand order of the commutative op, e.g. op(%s1,%s0) as well as op(%s0,%s1)."
    ],
    "instcombine_impl_hint": {
      "binary_ops": "In SimplifySelectsFeedingBinaryOp or equivalent, detect op(select(c,x,y), select(c,y,x)) for commutative opcodes and replace with op(x,y).",
